<template>
    <view class="co">
        <u-navbar title="予約詳細" :safeAreaInsetTop="true" :border="true" :placeholder="true" autoBack>
            <view class="u-nav-slot" slot="left">
                <u-icon name="arrow-left" size="19"></u-icon>
            </view>
            <view class="u-nav-slot" slot="right">
                <text style="color: #D93025;" @click="toEdit">編集</text>
            </view>
        </u-navbar>
        <view class="content">
            <view class="coTime" v-text="`${info.day} ${info.time}`"></view>
            <view class="item">
                <view class="item_left">
                    氏名
                </view>
                <view class="item_right">
                    <text style="color:#1A73E8" v-text="`${info.name}`"></text>
                </view>
            </view>
            <view class="item">
                <view class="item_left">
                    電話番号
                </view>
                <view class="item_right">
                    <text v-text="`${info.phone}`"></text>
                </view>
            </view>
            <view class="item">
                <view class="item_left">
                    会員ID
                </view>
                <view class="item_right">
                    <text v-text="`${info.member_id}`"></text>
                </view>
            </view>
            <view class="item">
                <view class="item_left">
                    予約番号
                </view>
                <view class="item_right">
                    <text v-text="`${info.order_no}`"></text>
                </view>
            </view>
        </view>
        <view class="content">
            <view class="detail" v-text="`${info.menu.title}`"></view>
            <view class="tiem">
                <view class="time" v-text="`所要時間：${info.menu.order_time}分`"></view>
                <view class="price" v-text="`￥${info.menu.price}`"></view>
            </view>
        </view>
        <view class="content">
            <view class="item">
                <view class="item_left">
                    指名担当
                </view>
                <view class="item_right">
                    <view class="squ" :style="info.appoint_admin? 'background:'+info.appoint_admin.color : 'background: #d2d2d7;'">
                    </view>
                    <view class="pname">
                        {{info.appoint_admin? info.appoint_admin.name : '指名無し'}}
                    </view>
                </view>
            </view>
            <view class="item">
                <view class="item_left">
                    当日担当
                </view>
                <view class="item_right">
                    <view class="squ" :style="`background: ${info.day_admin.color}`"></view>
                    <view class="pname" v-text="`${info.day_admin.name}`"></view>
                </view>
            </view>
        </view>
        <view class="content">
            <view>メモ</view>
            <view style="margin-top: 32upx;" v-text="`${info.remark}`"></view>
        </view>
        <view class="tips">
            <view>予約内容の変更をお客さんに伝えたい場合は</view>
            <view class="connect">こちら</view>
        </view>
        <u-popup :show="show"></u-popup>
    </view>
</template>

<script>
    import {
        getAppointOrderDetail
    } from '@/api/index.js'
    export default {
        data() {
            return {
                show: false,
                info: {},
                id:""
            };
        },
        created() {
           
        },
        onLoad(options) {
            let that = this
            let query = options
            that.id = query.id
            that.getDetail(query.id)
        },
        methods: {
            toEdit() {
                let that = this
                uni.navigateTo({
                    url: "../detail/edit?id="+that.id
                })
            },
            getDetail(id) {
                let that = this
                getAppointOrderDetail(id).then((res) => {
                    console.log(res)
                    if (res.code == 200) {
                        that.info = res.data.order
                    } else {
                        uni.showToast({
                            title: res.message
                        })
                    }
                })
            }
        }
    }
</script>

<style lang="scss">
    .co {
        box-sizing: border-box;
        padding: 0 40upx;

        .tips {
            box-sizing: border-box;
            padding: 28upx;
            background: #F5F5F7;
            color: #1D1D1F;
            border-radius: 20upx;
            font-size: 28upx;
            margin-top: 80upx;

            .connect {
                color: #1A73E8;
                margin-top: 20upx;
            }
        }

        .content {
            border-bottom: 2upx solid #d2d2d7;
            box-sizing: border-box;
            padding: 32upx 0 58upx 0;

            .detail {
                font-size: 32upx;
                font-family: Hiragino Sans-W5, Hiragino Sans;
                font-weight: normal;
                color: #1D1D1F;
            }

            .tiem {
                display: flex;
                align-items: center;
                font-size: 32upx;
                font-family: Hiragino Sans-W3, Hiragino Sans;
                font-weight: normal;
                margin-top: 20upx;

                .price {
                    color: rgba(217, 48, 37, 0.65);
                }

                .time {
                    color: #1D1D1F;
                }

            }

            .coTime {
                font-size: 24upx;
                font-family: Hiragino Sans-W3, Hiragino Sans;
                font-weight: normal;
                color: #AAAAAA;
                text-align: right;
            }

            .item {
                display: flex;
                align-items: center;
                margin-top: 32upx;
                font-size: 32upx;
                font-family: Hiragino Sans-W3, Hiragino Sans;
                font-weight: normal;
                color: #707070;

                .item_left {
                    width: 160upx;
                }

                .item_right {
                    display: flex;
                    align-items: center;

                    .squ {
                        width: 32upx;
                        height: 32upx;
                        border-radius: 8upx;
                        margin-right: 20upx;
                    }
                }
            }
        }
    }
</style>
